query.sparql:
SELECT ?item ?itemLabel
WHERE
{
  ?item wdt:P31 wd:Q729 .
  ?item p:P4624 ?statement .
  ?statement ps:P4624 wd:Q625657 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?entity ?entityLabel
WHERE
{
  ?entity wdt:P451 wd:Q4205826 .
  ?entity wdt:P451 wd:Q4463198 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?founder ?party WHERE {
  wd:Q8797 wdt:P112 ?founder .
  ?founder wdt:P102 ?party .
  ?founder wdt:P39 wd:Q169658 .
}

SELECT ?work ?workLabel
WHERE {
  ?author wdt:P50 ?work .
  ?work wdt:P50 ?author .
  ?author wdt:P50 wd:Q216476 .
  ?work wdt:P31 wd:Q47461344 .
  ?work wdt:P921 ?theme .
  ?theme wdt:P31 wd:Q207627 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?work ?workLabel
WHERE
{
  ?author wdt:P50 ?book .
  ?book wdt:P6333 ?work .
  FILTER NOT EXISTS { ?book wdt:P6333 "The Witcher" . }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?item ?itemLabel
WHERE
{
  wd:Q231121 wdt:P69 ?item.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
